/// Return the HTTP status code for the error pointed to by `err`.
/// Returns `0` if `err` is null.
#[no_mangle]
pub unsafe extern "C" fn spikard_graph_q_l_error_status_code(err: *const spikard_graphql::error::GraphQLError) -> u16 {
    // SAFETY: caller guarantees `err` points to a live `spikard_graphql::error::GraphQLError` value
    // allocated by this library, or is null.
    if err.is_null() {
        return 0;
    }
    (*err).status_code()
}

/// Return whether the error pointed to by `err` is transient.
/// Returns `false` if `err` is null.
#[no_mangle]
pub unsafe extern "C" fn spikard_graph_q_l_error_is_transient(
    err: *const spikard_graphql::error::GraphQLError,
) -> bool {
    // SAFETY: caller guarantees `err` points to a live `spikard_graphql::error::GraphQLError` value
    // allocated by this library, or is null.
    if err.is_null() {
        return false;
    }
    (*err).is_transient()
}

/// Return the machine-readable error category string for the error pointed
/// to by `err` as a heap-allocated, NUL-terminated C string.
/// The caller must free the returned pointer with `spikard_graph_q_l_error_error_type_free`.
/// Returns a null pointer if `err` is null.
#[no_mangle]
pub unsafe extern "C" fn spikard_graph_q_l_error_error_type(
    err: *const spikard_graphql::error::GraphQLError,
) -> *mut std::ffi::c_char {
    // SAFETY: caller guarantees `err` points to a live `spikard_graphql::error::GraphQLError` value
    // allocated by this library, or is null.
    if err.is_null() {
        return std::ptr::null_mut();
    }
    let s = (*err).error_type();
    // SAFETY: `error_type()` returns a `'static str` containing no NUL bytes.
    std::ffi::CString::new(s)
        .map(|c| c.into_raw())
        .unwrap_or(std::ptr::null_mut())
}

/// Free a string previously returned by `spikard_graph_q_l_error_error_type`.
/// Passing a null pointer is a no-op.
#[no_mangle]
pub unsafe extern "C" fn spikard_graph_q_l_error_error_type_free(ptr: *mut std::ffi::c_char) {
    // SAFETY: `ptr` was allocated by `CString::into_raw` inside
    // `spikard_graph_q_l_error_error_type` and is now being reclaimed by the matching
    // `CString::from_raw`.  Passing null is explicitly allowed.
    if !ptr.is_null() {
        drop(std::ffi::CString::from_raw(ptr));
    }
}
